gryffindor = 0hufflepuff = 0ravenclaw = 0slytherin = 0question1 = """Q1) Do you like Dawn or Dusk?    1) Dawn    2) DuskChoice (1-2): """question2: str = """Q2) When I’m dead, I want people to remember me as:    1) The Good    2) The Great    3) The Wise    4) The BoldChoice (1-4): """question3 = """Q3) Which kind of instrument most pleases your ear?    1) The violin    2) The trumpet    3) The piano    4) The drumChoice (1-4): """answer1 = int(input(question1))if answer1 == 1:  gryffindor += 1  ravenclaw += 1elif answer1 == 2:  hufflepuff += 1  slytherin += 1else:  print("Wrong Input.")answer2 = int(input(question2))if answer2 == 1:  hufflepuff += 2elif answer2 == 2:  slytherin += 2elif answer2 == 3:  ravenclaw += 2elif answer2 == 4:  gryffindor += 2else:  print("Wrong Input.")answer3 = int(input(question3))if answer3 == 1:  slytherin += 4elif answer3 == 2:  hufflepuff += 4elif answer3 == 3:  ravenclaw += 4elif answer3 == 4:  gryffindor += 4else:  print("Wrong Input.")print("\nSorting Hat says:")print("🔴 Gryffindor:", gryffindor)print("🟡 Hufflepuff:", hufflepuff)print("🔵 Ravenclaw :", ravenclaw)print("🟢 Slytherin :", slytherin)house_score = max(gryffindor, hufflepuff, ravenclaw, slytherin)if house_score <= 1:  print("\nHmm... this is most unusual...")  print("I cannot decide... the choice is yours.")else:  print("\nAh... yes...")  print("I see it clearly now.")  print("BETTER BE...\n")  if gryffindor == house_score:    print("  🦁 GRYFFINDOR! 🦁")  elif hufflepuff == house_score:    print("  🦡 HUFFLEPUFF! 🦡")  elif ravenclaw == house_score:    print("  🦅 RAVENCLAW! 🦅")  else:    print("  🐍 SLYTHERIN! 🐍")